export const shootingRanges = marylandShootingRanges;

const BASIC_STATS = {
  totalLands: marylandPublicLands.length,
  totalRanges: marylandShootingRanges.length,
  withPolygons: marylandPublicLands.filter(l => l.geometry !== null).length,
  withCenterOnly: marylandPublicLands.filter(l => l.geometry === null && l.center !== null).length,
  withParking: marylandPublicLands.filter(l => l.parking !== null && l.parking.length > 0).length,
  withWebsite: marylandPublicLands.filter(l => l.websiteUrl !== null).length,
  withPdfMap: marylandPublicLands.filter(l => l.dnrMapPdf !== null).length,
};

// ─────────────────────────────────────────────────────────────────────────────
// HELPER FUNCTIONS
// ─────────────────────────────────────────────────────────────────────────────

export function searchLands(query: string): MarylandPublicLand[] {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return marylandPublicLands.filter(
    (land) =>
      land.name.toLowerCase().includes(q) ||
      land.county.toLowerCase().includes(q) ||
      land.designation.toLowerCase().includes(q) ||
      land.designationFull.toLowerCase().includes(q)
  );
}

export function filterLands(filters: {
  species?: string;
  weapon?: string;
  county?: string;
  designation?: LandDesignation;
  sundayHunting?: boolean;
}): MarylandPublicLand[] {
  return marylandPublicLands.filter((land) => {
    if (filters.species && !land.huntableSpecies.some((s) => s.toLowerCase().includes(filters.species!.toLowerCase()))) return false;
    if (filters.weapon && !land.allowedWeapons.some((w) => w.toLowerCase().includes(filters.weapon!.toLowerCase()))) return false;
    if (filters.county && land.county.toLowerCase() !== filters.county.toLowerCase()) return false;
    if (filters.designation && land.designation !== filters.designation) return false;
    if (filters.sundayHunting !== undefined && land.sundayHunting !== filters.sundayHunting) return false;
    return true;
  });
}

export function getLandsByCounty(county: string): MarylandPublicLand[] {
  const c = county.toLowerCase().trim();
  return marylandPublicLands.filter(
    (land) => land.county.toLowerCase() === c
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// EXTENDED STATS (used by chatKnowledge)
// ─────────────────────────────────────────────────────────────────────────────

const uniqueCounties = new Set(marylandPublicLands.map((l) => l.county));

const designationCounts: Record<string, number> = {};
marylandPublicLands.forEach((l) => {
  designationCounts[l.designation] = (designationCounts[l.designation] || 0) + 1;
});

export const DATA_STATS = {
  ...BASIC_STATS,
  countiesWithLands: uniqueCounties.size,
  landsByDesignation: {
    WMA: designationCounts['WMA'] || 0,
    SF: designationCounts['SF'] || 0,
    SP: designationCounts['SP'] || 0,
    CFL: designationCounts['CFL'] || 0,
    CWMA: designationCounts['CWMA'] || 0,
    NRMA: designationCounts['NRMA'] || 0,
    NEA: designationCounts['NEA'] || 0,
    FMA: designationCounts['FMA'] || 0,
  },
};
